// Extract connection info from Edge Function trigger
const body = $input.first().json.body || $input.first().json;
const operatorId = body.operator_id;
const connectionId = body.connection_id;
const hospitableCustomerId = body.hospitable_customer_id;
const hospitableConnectionId = body.hospitable_connection_id;

if (!operatorId || !hospitableCustomerId) {
  throw new Error('Missing operator_id or hospitable_customer_id');
}

return [{
  json: {
    operatorId,
    connectionId,
    hospitableCustomerId,
    hospitableConnectionId,
    page: 1,
    perPage: 50
  }
}];

// Transform Hospitable listings to nfs_properties format
const response = $input.first().json;
const listings = response.data || response.listings || [];
const meta = response.meta || {};
const operatorId = $('Parse Trigger Payload').first().json.operatorId;
const hospitableCustomerId = $('Parse Trigger Payload').first().json.hospitableCustomerId;
const hospitableConnectionId = $('Parse Trigger Payload').first().json.hospitableConnectionId;

const properties = listings.map(listing => {
  const cleaningFeeEntry = Array.isArray(listing.fees) ? listing.fees.find(f => f.type === 'CLEANING') : null;
  return {
    operator_id: operatorId,
    source: 'airbnb',
    status: 'completed',
    listing_status: 'listed',
    hospitable_property_id: listing.id || listing.listing_id,
    hospitable_connected: true,
    hospitable_last_sync_at: new Date().toISOString(),
    hospitable_sync_status: 'completed',
    hospitable_connection_id: hospitableConnectionId,
    hospitable_customer_id: hospitableCustomerId,
    hospitable_platform_mappings: listing.platform_mappings || listing.channels || [],
    public_title: listing.public_name || listing.name || listing.title || '',
    internal_title: listing.private_name || listing.public_name || '',
    description: listing.description || listing.summary || '',
    property_type: listing.property_type || 'apartment',
    address: listing.address?.street || '',
    city: listing.address?.city || '',
    state: listing.address?.state || '',
    country: listing.address?.country_code || 'GB',
    postal_code: listing.address?.zipcode || '',
    lat: listing.address?.latitude || listing.latitude || null,
    lng: listing.address?.longitude || listing.longitude || null,
    max_guests: listing.capacity?.max || 4,
    room_counts: listing.rooms || [],
    images: listing.picture ? [{ url: listing.picture.replace(/\\?aki_policy=[^&]+/, ''), caption: '', order: 0, is_cover: true }] : [],
    amenities: listing.amenities || [],
    check_in_time: listing.check_in || '15:00',
    check_out_time: listing.check_out || '11:00',
    rules: listing.house_rules || '',
    base_rate_amount: listing.base_price || listing.price?.base || 100,
    base_rate_currency: listing.currency || 'GBP',
    minimum_stay: listing.minimum_nights || 1,
    cleaning_fee: cleaningFeeEntry ? { enabled: true, amount: cleaningFeeEntry.amount } : { enabled: false }
  };
});

return [{
  json: {
    properties,
    hasMore: meta.current_page < meta.last_page,
    nextPage: (meta.current_page || 1) + 1,
    totalListings: meta.total || listings.length
  }
}];

// Upsert each property via Supabase REST API
const properties = $input.first().json.properties;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const results = [];

for (const prop of properties) {
  try {
    const existing = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}/rest/v1/nfs_properties?hospitable_property_id=eq.${prop.hospitable_property_id}`,
      headers: {
        'apikey': serviceKey,
        'Authorization': `Bearer ${serviceKey}`,
        'Accept': 'application/json'
      }
    });

    if (existing && existing.length > 0) {
      // Update existing
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${supabaseUrl}/rest/v1/nfs_properties?id=eq.${existing[0].id}`,
        headers: {
          'apikey': serviceKey,
          'Authorization': `Bearer ${serviceKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: prop
      });
      results.push({ id: existing[0].id, action: 'updated' });
    } else {
      // Insert new
      const inserted = await this.helpers.httpRequest({
        method: 'POST',
        url: `${supabaseUrl}/rest/v1/nfs_properties`,
        headers: {
          'apikey': serviceKey,
          'Authorization': `Bearer ${serviceKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=representation'
        },
        body: prop
      });
      results.push({ id: inserted[0]?.id, action: 'inserted' });
    }
  } catch (err) {
    results.push({ hospitable_id: prop.hospitable_property_id, action: 'error', error: err.message });
  }
}

return [{ json: { results, count: results.length, hasMore: $input.first().json.hasMore, nextPage: $input.first().json.nextPage } }];

// Transform Hospitable reservations to nfs_reservations format
const response = $input.first().json;
const reservations = response.data || response.reservations || [];
const operatorId = $('Parse Trigger Payload').first().json.operatorId;
const hospitableConnectionId = $('Parse Trigger Payload').first().json.hospitableConnectionId;

const mapped = reservations.map(res => ({
  operator_id: operatorId,
  booking_source: 'main_platform',
  hospitable_reservation_id: res.id || res.reservation_id,
  hospitable_platform: res.platform || res.channel || 'airbnb',
  hospitable_platform_id: res.platform_id || res.external_id || '',
  hospitable_connection_id: hospitableConnectionId,
  hospitable_status: res.status || 'confirmed',
  hospitable_financials: res.financials || res.pricing || {},
  hospitable_last_sync_at: new Date().toISOString(),
  check_in: res.check_in || res.start_date,
  check_out: res.check_out || res.end_date,
  check_in_time: res.check_in_time || '15:00',
  check_out_time: res.check_out_time || '11:00',
  guest_first_name: res.guest?.first_name || res.guest_name?.split(' ')[0] || '',
  guest_last_name: res.guest?.last_name || res.guest_name?.split(' ').slice(1).join(' ') || '',
  guest_email: res.guest?.email || '',
  guest_phone: res.guest?.phone || '',
  adults: res.guests?.adults || res.number_of_guests || 1,
  children: res.guests?.children || 0,
  total_amount: res.total_price || res.financials?.total || 0,
  payment_status: res.payment_status || 'paid',
  status: res.status === 'cancelled' ? 'cancelled' : 'confirmed'
}));

return [{ json: { reservations: mapped, count: mapped.length } }];

// Upsert each reservation via Supabase REST API
const reservations = $input.first().json.reservations;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const results = [];

// We need to look up property_id from hospitable_property_id for each reservation
for (const res of reservations) {
  try {
    // Check if reservation already exists
    const existing = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}/rest/v1/nfs_reservations?hospitable_reservation_id=eq.${res.hospitable_reservation_id}`,
      headers: {
        'apikey': serviceKey,
        'Authorization': `Bearer ${serviceKey}`,
        'Accept': 'application/json'
      }
    });

    if (existing && existing.length > 0) {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${supabaseUrl}/rest/v1/nfs_reservations?id=eq.${existing[0].id}`,
        headers: {
          'apikey': serviceKey,
          'Authorization': `Bearer ${serviceKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: res
      });
      results.push({ id: existing[0].id, action: 'updated' });
    } else {
      const inserted = await this.helpers.httpRequest({
        method: 'POST',
        url: `${supabaseUrl}/rest/v1/nfs_reservations`,
        headers: {
          'apikey': serviceKey,
          'Authorization': `Bearer ${serviceKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=representation'
        },
        body: res
      });
      results.push({ id: inserted[0]?.id, action: 'inserted' });
    }
  } catch (err) {
    results.push({ hospitable_id: res.hospitable_reservation_id, action: 'error', error: err.message });
  }
}

return [{ json: { results, count: results.length } }];

// Update connection with sync results
const propertyResults = $('Upsert Properties to Supabase').first().json;
const reservationResults = $input.first().json;
const connectionId = $('Parse Trigger Payload').first().json.connectionId;

return [{
  json: {
    connectionId,
    sync_status: 'completed',
    total_properties: propertyResults.count || 0,
    total_reservations: reservationResults.count || 0,
    last_sync_at: new Date().toISOString(),
    last_sync_results: {
      properties: propertyResults.results || [],
      reservations: reservationResults.results || [],
      completed_at: new Date().toISOString()
    }
  }
}];
